queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?approach_value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasApproaches ?child ; p:hasMarketing_Campaigns ?parent . } GROUP BY ?child }
  ?child p:approach_value ?approach_value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Marketing_Campaigns } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?campaign_name ?approach_value WHERE {
  ?marketing_campaigns_approaches a :Marketing_Campaigns_Approaches .
  ?approaches a :Approaches .
  ?marketing_campaigns_approaches p:hasApproaches ?approaches .
  ?marketing_campaigns a :Marketing_Campaigns .
  ?marketing_campaigns_approaches p:hasMarketing_Campaigns ?marketing_campaigns .
  ?marketing_campaigns p:campaign_name ?campaign_name .
  ?approaches p:approach_value ?approach_value .
} }
  collective: { SELECT ?approach_value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasApproaches ?child ; p:hasMarketing_Campaigns ?parent . } GROUP BY ?child }
  ?child p:approach_value ?approach_value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Marketing_Campaigns } }
  FILTER(?nf = ?total)
} }
}
